class Solution {
public:
    int minSwaps(vector<int>& nums) {
        int n = nums.size();
        int ones = 0;
        for (int num : nums) {
            if (num == 1) ones++;
        }

        if (ones == 0) return 0;

        int window_ones = 0;
        for (int i = 0; i < ones; i++) {
            if (nums[i] == 1) window_ones++;
        }

        int min_swaps = ones - window_ones;
        for (int i = ones; i < n + ones; i++) {
            if (i < n && nums[i] == 1) window_ones++;
            if (i >= n && nums[i - n] == 1) window_ones--;
            min_swaps = min(min_swaps, ones - window_ones);
        }

        return min_swaps;
    }
};
